# compute similarity function

def token_f1(a,b):
    atoks = a.split()
    btoks = b.split()
    if not atoks or not btoks:
        return 0.0
    atset = {}
    for t in atoks:
        atset[t] = atset.get(t,0)+1
    bset = {}
    for t in btoks:
        bset[t] = bset.get(t,0)+1
    # compute overlap count
    overlap = 0
    for t,c in atset.items():
        overlap += min(c, bset.get(t,0))
    prec = overlap / len(atoks)
    rec = overlap / len(btoks)
    if prec+rec == 0:
        return 0.0
    return 2*prec*rec/(prec+rec)

# LCS longest common substring? They suggested LCS or n-grams. We'll compute longest common substring (consecutive) length using dynamic programming for characters.
def longest_common_substring_len(a,b):
    # dynamic programming O(len(a)*len(b))
    la = len(a)
    lb = len(b)
    if la==0 or lb==0:
        return 0
    dp = [[0]*(lb+1) for _ in range(la+1)]
    longest = 0
    for i in range(1, la+1):
        ai = a[i-1]
        row = dp[i]
        prev = dp[i-1]
        for j in range(1, lb+1):
            if ai == b[j-1]:
                row[j] = prev[j-1] + 1
                if row[j] > longest:
                    longest = row[j]
            else:
                row[j] = 0
    return longest

def similarity_score(candidate_norm, query_norm):
    # token F1
    f1 = token_f1(candidate_norm, query_norm)
    # LCS substring ratio relative to max length of candidate or query? They suggested robust: use LCS / len(candidate_norm)
    lcslen = longest_common_substring_len(candidate_norm, query_norm)
    if len(candidate_norm) ==0:
        lcs_ratio = 0
    else:
        lcs_ratio = lcslen / len(candidate_norm)
    return max(f1, lcs_ratio), f1, lcs_ratio

